import{useIsomorphicLayoutEffect}from"../lib/useIsomorphicLayoutEffect.js";import{useStableCallback}from"./useStableCallback.js";const useMutationObserver=(t,e)=>{const s=useStableCallback(e);useIsomorphicLayoutEffect(()=>{if(t&&t.current){const e=new MutationObserver(s);return e.observe(t.current,{subtree:!0,childList:!0}),()=>e.disconnect()}},[t,s])};export{useMutationObserver};